package com.example.demo.proto;

/**
 * Minimal hand-written stub of generated GreeterGrpc to satisfy IDE/compiler when protobuf plugin
 * hasn't generated classes yet.
 */
public final class GreeterGrpc {
    private GreeterGrpc() {}

    public abstract static class GreeterImplBase implements io.grpc.BindableService {

        /**
         * Default implementation; override in service implementation.
         */
        public void sayHello(HelloProto.HelloRequest request, io.grpc.stub.StreamObserver<HelloProto.HelloReply> responseObserver) {
            responseObserver.onError(new UnsupportedOperationException("Not implemented"));
        }

        @Override
        public io.grpc.ServerServiceDefinition bindService() {
            // Provide a minimal service definition so the server binder can accept it.
            return io.grpc.ServerServiceDefinition.builder("helloworld.Greeter").build();
        }
    }
}
